import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"大栅栏","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/dashilan.md","filePath":"landmarks/dashilan.md","lastUpdated":1784773307000}'),n={name:"landmarks/dashilan.md"};function d(s,t,i,o,h,g){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="大栅栏" tabindex="-1">大栅栏 <a class="header-anchor" href="#大栅栏" aria-label="Permalink to &quot;大栅栏&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-3bqa0rGhVSA?w=1200" alt="大栅栏"></p><blockquote><p>&quot;百年商街，老北京的商业记忆。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>大栅栏位于北京市西城区前门大街西侧，是北京最著名的商业街之一。大栅栏始建于明代，兴盛于清代，是北京城最繁华的商业区之一。这里汇聚了众多百年老字号，是北京商业文化的代表。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">全天开放</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">2-3小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁2号线前门站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市西城区大栅栏街</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="明代形成" tabindex="-1">明代形成 <a class="header-anchor" href="#明代形成" aria-label="Permalink to &quot;明代形成&quot;">​</a></h3><p>大栅栏始建于明代，当时为了防盗，在街巷两端设置了栅栏，因此得名&quot;大栅栏&quot;。</p><h3 id="清代繁荣" tabindex="-1">清代繁荣 <a class="header-anchor" href="#清代繁荣" aria-label="Permalink to &quot;清代繁荣&quot;">​</a></h3><p>清代是大栅栏最繁荣的时期。康熙年间，大栅栏成为北京城最繁华的商业区之一，汇聚了众多商铺和戏楼。</p><h4 id="商业繁荣" tabindex="-1">商业繁荣 <a class="header-anchor" href="#商业繁荣" aria-label="Permalink to &quot;商业繁荣&quot;">​</a></h4><ul><li><strong>商铺林立</strong>：各种商铺鳞次栉比</li><li><strong>戏楼众多</strong>：是京剧的发源地之一</li><li><strong>会馆聚集</strong>：各地会馆在此设立</li></ul><h3 id="近代变迁" tabindex="-1">近代变迁 <a class="header-anchor" href="#近代变迁" aria-label="Permalink to &quot;近代变迁&quot;">​</a></h3><p>民国时期，大栅栏继续繁荣。新中国成立后，大栅栏进行了多次改造，保持了传统的商业风貌。</p><h2 id="主要景点" tabindex="-1">主要景点 <a class="header-anchor" href="#主要景点" aria-label="Permalink to &quot;主要景点&quot;">​</a></h2><h3 id="老字号商铺" tabindex="-1">老字号商铺 <a class="header-anchor" href="#老字号商铺" aria-label="Permalink to &quot;老字号商铺&quot;">​</a></h3><p>大栅栏汇聚了众多百年老字号，是北京商业文化的代表。</p><h4 id="知名老字号" tabindex="-1">知名老字号 <a class="header-anchor" href="#知名老字号" aria-label="Permalink to &quot;知名老字号&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">老字号</th><th style="text-align:left;">特色</th><th style="text-align:left;">地址</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>瑞蚨祥</strong></td><td style="text-align:left;">绸缎</td><td style="text-align:left;">大栅栏街5号</td></tr><tr><td style="text-align:left;"><strong>内联升</strong></td><td style="text-align:left;">布鞋</td><td style="text-align:left;">大栅栏街34号</td></tr><tr><td style="text-align:left;"><strong>步瀛斋</strong></td><td style="text-align:left;">布鞋</td><td style="text-align:left;">大栅栏街</td></tr><tr><td style="text-align:left;"><strong>盛锡福</strong></td><td style="text-align:left;">帽子</td><td style="text-align:left;">大栅栏街</td></tr><tr><td style="text-align:left;"><strong>广誉远</strong></td><td style="text-align:left;">中药</td><td style="text-align:left;">大栅栏街</td></tr><tr><td style="text-align:left;"><strong>同仁堂</strong></td><td style="text-align:left;">中药</td><td style="text-align:left;">大栅栏街</td></tr></tbody></table><h3 id="戏楼文化" tabindex="-1">戏楼文化 <a class="header-anchor" href="#戏楼文化" aria-label="Permalink to &quot;戏楼文化&quot;">​</a></h3><p>大栅栏是北京京剧的发源地之一，历史上曾有众多戏楼。</p><h4 id="著名戏楼" tabindex="-1">著名戏楼 <a class="header-anchor" href="#著名戏楼" aria-label="Permalink to &quot;著名戏楼&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">戏楼</th><th style="text-align:left;">特色</th><th style="text-align:left;">现状</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>广和楼</strong></td><td style="text-align:left;">京剧发源地之一</td><td style="text-align:left;">已修复</td></tr><tr><td style="text-align:left;"><strong>三庆园</strong></td><td style="text-align:left;">京剧名角演出地</td><td style="text-align:left;">已修复</td></tr><tr><td style="text-align:left;"><strong>庆乐园</strong></td><td style="text-align:left;">京剧演出场所</td><td style="text-align:left;">已修复</td></tr></tbody></table><h3 id="会馆建筑" tabindex="-1">会馆建筑 <a class="header-anchor" href="#会馆建筑" aria-label="Permalink to &quot;会馆建筑&quot;">​</a></h3><p>大栅栏周边曾有众多会馆建筑，是各地商人在京的聚集地。</p><h4 id="主要会馆" tabindex="-1">主要会馆 <a class="header-anchor" href="#主要会馆" aria-label="Permalink to &quot;主要会馆&quot;">​</a></h4><ul><li><strong>湖广会馆</strong>：湖南、湖北商人会馆</li><li><strong>江西会馆</strong>：江西商人会馆</li><li><strong>山西会馆</strong>：山西商人会馆</li></ul><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>精华路线（约2小时）</strong>：</p><p>前门地铁站 → 前门大街 → 大栅栏街 → 瑞蚨祥 → 内联升 → 广和楼 → 鲜鱼口 → 小吃街</p><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>最佳时间</strong>：工作日人较少，适合慢慢逛</li><li><strong>购物建议</strong>：老字号商品价格较高，但品质有保障</li><li><strong>拍照打卡</strong>：大栅栏的牌坊、老字号店铺都是绝佳拍照点</li><li><strong>美食推荐</strong>：大栅栏周边有很多北京特色小吃</li><li><strong>周边游览</strong>：可以与前门大街、鲜鱼口一起游览</li></ol><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">路线</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>地铁</strong></td><td style="text-align:left;">2号线前门站B口或C口</td></tr><tr><td style="text-align:left;"><strong>公交</strong></td><td style="text-align:left;">1、2、52、82、120路前门站</td></tr><tr><td style="text-align:left;"><strong>打车</strong></td><td style="text-align:left;">定位&quot;大栅栏&quot;即可</td></tr></tbody></table><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">前门大街</td><td style="text-align:center;">步行1分钟</td><td style="text-align:left;">老北京商业街</td></tr><tr><td style="text-align:left;">鲜鱼口</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">小吃街</td></tr><tr><td style="text-align:left;">天安门广场</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">世界最大城市广场</td></tr><tr><td style="text-align:left;">国家博物馆</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">国家级博物馆</td></tr><tr><td style="text-align:left;">故宫</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">明清皇宫</td></tr></tbody></table><h2 id="文化意义" tabindex="-1">文化意义 <a class="header-anchor" href="#文化意义" aria-label="Permalink to &quot;文化意义&quot;">​</a></h2><p>大栅栏是北京商业文化的代表，也是老北京生活方式的缩影。在这里，你可以感受到老北京的商业氛围，也可以体验到传统手工艺的魅力。</p><p>&quot;头顶马聚源，脚踩内联升，身穿瑞蚨祥，腰缠四大恒&quot;，这句老话形象地描述了老北京人对大栅栏的印象。</p><hr><p><strong>📍 地址</strong>：北京市西城区大栅栏街 <strong>🚇 地铁</strong>：2号线前门站B口或C口</p><p><strong>💡 Tips</strong>：大栅栏的老字号商品价格较高，但品质有保障。建议购买一些作为纪念品。</p>',45)])])}const y=e(n,[["render",d]]);export{f as __pageData,y as default};
